INSERT INTO symmetry_groups (symmetry_group_id, notation, orbifold, display_name, description, lattice_type, lattice_angle_deg, lattice_ratio, generators, rotation_order, operation_count, has_mirrors, has_glides)
VALUES ('p1', 'p1', 'o', 'Translations only', 'Only translations; no rotations, reflections, or glides. The most general wallpaper group.', 'oblique', 73, 1.3, '[]', 1, 1, FALSE, FALSE) ON CONFLICT (symmetry_group_id) DO NOTHING;

